        let data = self.data.read();
        let ids = self.ids.read();
        let n = self.count.load(Ordering::Acquire);

        let k = top_k as usize;

        // Parallel distance computation using par_chunks_exact with heap
        let chunk_top_k = k.max(100); // Keep more results per chunk for better accuracy

        // Process in parallel, each chunk maintains its own top-k
        let local_heaps: Vec<BinaryHeap<Reverse<(f64, u64)>>> = data
            .par_chunks_exact(DIM)
            .enumerate()
            .fold(
                || BinaryHeap::with_capacity(chunk_top_k),
