#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
unsafe fn l2_distance_avx512_inline(a: *const f32, b: *const f32) -> f64 {
    use std::arch::x86_64::*;

    let mut sum = _mm512_setzero_ps();

    // Process 16 floats at a time (128 / 16 = 8 iterations)
    for i in 0..8 {
        let va = _mm512_loadu_ps(a.add(i * 16));
        let vb = _mm512_loadu_ps(b.add(i * 16));
        let diff = _mm512_sub_ps(va, vb);
        sum = _mm512_fmadd_ps(diff, diff, sum);
    }

    _mm512_reduce_add_ps(sum) as f64
}

pub fn l2_distance_optimized(a: &[f32], b: &[f32]) -> f64 {
    #[cfg(target_arch = "x86_64")]
    {
        if is_avx512_supported() {
            unsafe { l2_distance_avx512_inline(a.as_ptr(), b.as_ptr()) }
        } else {
            a.iter()
                .zip(b.iter())
                .map(|(x, y)| {
                    let diff = *x - *y;
                    diff * diff
                })
                .sum::<f32>() as f64
        }
    }
    #[cfg(not(target_arch = "x86_64"))]
    {
        a.iter()
            .zip(b.iter())
            .map(|(x, y)| {
                let diff = *x - *y;
                diff * diff
            })
            .sum::<f32>() as f64
    }
}

#[cfg(target_arch = "x86_64")]
fn is_avx512_supported() -> bool {
    use std::arch::x86_64::__cpuid;
    unsafe {
        let eax7 = __cpuid(7);
        (eax7.ebx & (1 << 16)) != 0
    }
}

