const DIM: usize = 128;
const BATCH_SIZE: usize = 16384; // Process this many vectors per parallel task

impl VectorDB {
    pub fn new() -> Self {
        Self {
            data: RwLock::new(Vec::with_capacity(1_000_000 * DIM)),
            ids: RwLock::new(Vec::with_capacity(1_000_000)),
